static const int D2CLIENT_NUM_ITEM_BASES = sizeof(g_ClientItemBases) / sizeof(g_ClientItemBases[0]);

// Binary search for item base flags. Returns -1 if not found.
static int D2Client_GetItemBaseFlags(const char* code)
{
	int lo = 0, hi = D2CLIENT_NUM_ITEM_BASES - 1;
	while (lo <= hi)
	{
		int mid = (lo + hi) / 2;
		int cmp = strncmp(code, g_ClientItemBases[mid].code, 4);
		if (cmp == 0) return g_ClientItemBases[mid].flags;
		if (cmp < 0) hi = mid - 1;
		else lo = mid + 1;
	}
	return -1;
}
